size_t stator_string_write_utf8(const struct StatorValue *val,
                                char *buf,
                                size_t buf_size,
                                size_t *nchars_ref);

/**
 * Create a new number value (V8-style spelling of [`stator_value_new_number`]).
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorValue *stator_number_new(struct StatorIsolate *isolate, double val);

/**
 * Create a new integer value from a signed 64-bit integer.
 *
 * The value is stored as an ECMAScript `Number` (IEEE 754 double).  Values
 * outside the safe-integer range (`±2⁵³−1`) may lose precision.  Returns a
 * null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorValue *stator_integer_new(struct StatorIsolate *isolate, int64_t val);

/**
 * Create a new boolean value (V8-style spelling of [`stator_value_new_boolean`]).
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorValue *stator_boolean_new(struct StatorIsolate *isolate, bool val);

/**
 * Create a new `undefined` value (V8-style spelling of [`stator_value_new_undefined`]).
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorValue *stator_undefined_new(struct StatorIsolate *isolate);

/**
 * Create a new `null` value (V8-style spelling of [`stator_value_new_null`]).
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorValue *stator_null_new(struct StatorIsolate *isolate);

/**
 * Destroy a value and decrement the isolate's live-object counter.
 *
 * # Safety
 * `val` must be a non-null pointer returned by any `stator_value_new_*`
 * function and must not be used again after this call.
 */
void stator_value_destroy(struct StatorValue *val);

/**
 * Return a static C string describing the type of `val`: `"number"` or
 * `"string"`.
 *
 * Returns `"undefined"` when `val` is null.  The returned pointer is valid
 * for the lifetime of the process.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
const char *stator_value_type(const struct StatorValue *val);

/**
 * Return the numeric value stored in `val`, or `NaN` if `val` is null or not
 * a number.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
double stator_value_as_number(const struct StatorValue *val);

/**
 * Return a null-terminated C string for the string stored in `val`.
 *
 * Returns a pointer to an empty string (`""`) when `val` is null or not a
 * string.  The pointer is valid only as long as `val` is alive.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
const char *stator_value_as_string(const struct StatorValue *val);

/**
 * Returns `true` if `val` is the ECMAScript `undefined` value.
 *
 * A null `val` pointer is treated as `undefined` and also returns `true`.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_undefined(const struct StatorValue *val);

/**
 * Returns `true` if `val` is the ECMAScript `null` value.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_null(const struct StatorValue *val);

/**
 * Returns `true` if `val` holds a JavaScript string.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_string(const struct StatorValue *val);

/**
 * Returns `true` if `val` holds a JavaScript number.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_number(const struct StatorValue *val);

/**
 * Returns `true` if `val` holds a JavaScript boolean.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_boolean(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript object (excludes `null`).
 *
 * Arrays, dates, regexps, promises, maps, and sets are all objects in
 * ECMAScript and therefore also return `true`.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_object(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a callable JavaScript function.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_function(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript array.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_array(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a number whose value is a signed 32-bit integer.
 *
 * A value is considered an int32 when it is a finite number equal to its own
 * `ToInt32` conversion: i.e. it is an integer in the range `[−2³¹, 2³¹−1]`.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_int32(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a number whose value is an unsigned 32-bit integer.
 *
 * A value is considered a uint32 when it is a finite number equal to its own
 * `ToUint32` conversion: i.e. it is an integer in the range `[0, 2³²−1]`.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_uint32(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript `Date` object.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_date(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript `RegExp` object.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_regexp(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript `Promise` object.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_promise(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript `Map` object.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_map(const struct StatorValue *val);

/**
 * Returns `true` if `val` is a JavaScript `Set` object.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_is_set(const struct StatorValue *val);

/**
 * Create a new, empty JavaScript object.
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorObject *stator_object_new(struct StatorIsolate *isolate);

/**
 * Destroy an object and decrement the isolate's live-object counter.
 *
 * # Safety
 * `obj` must be a non-null pointer returned by `stator_object_new` and must
 * not be used again after this call.
 */
void stator_object_destroy(struct StatorObject *obj);

/**
 * Set (or overwrite) the named property `key` on `obj` to `val`.
 *
 * The value is copied by value into the object; the caller retains ownership
 * of `val` and must destroy it independently.  Does nothing if any argument
 * is null.
 *
 * # Safety
 * - `obj` must be a valid, live [`StatorObject`] pointer.
 * - `key` must be a valid, null-terminated C string.
 * - `val` must be a valid, live [`StatorValue`] pointer.
 */
void stator_object_set(struct StatorObject *obj, const char *key, const struct StatorValue *val);

/**
 * Get the named property `key` from `obj` as a new [`StatorValue`].
 *
 * Returns a null pointer if `obj` or `key` is null, or if the property does
 * not exist.  The caller owns the returned pointer and must pass it to
 * [`stator_value_destroy`].
 *
 * # Safety
 * - `obj` must be a valid, live [`StatorObject`] pointer.
 * - `key` must be a valid, null-terminated C string.
 */
struct StatorValue *stator_object_get(const struct StatorObject *obj, const char *key);

/**
 * Return `true` if `obj` has a property with the given `key` (own or
 * inherited via the prototype chain).
 *
 * Returns `false` if any argument is null.
 *
 * # Safety
 * - `obj` must be a valid, live [`StatorObject`] pointer.
 * - `key` must be a valid, null-terminated C string.
 */
bool stator_object_has(const struct StatorObject *obj, const char *key);

/**
 * Delete the named property `key` from `obj`.
 *
 * Returns `true` if the property was successfully deleted (or did not exist),
 * `false` if the deletion fails (e.g. the property is non-configurable, the
 * object is non-extensible in a way that prevents deletion, or any argument
 * is null).
 *
 * # Safety
 * - `obj` must be a valid, live [`StatorObject`] pointer.
 * - `key` must be a valid, null-terminated C string.
 */
bool stator_object_delete(struct StatorObject *obj, const char *key);

/**
 * Collect the own enumerable property names of `obj` into a new
 * [`StatorPropertyNames`] snapshot.
 *
 * Returns a null pointer if `obj` is null.  The caller must eventually pass
 * the returned pointer to [`stator_property_names_destroy`].
 *
 * # Safety
 * `obj` must be a valid, live [`StatorObject`] pointer.
 */
struct StatorPropertyNames *stator_object_get_property_names(const struct StatorObject *obj);

/**
 * Return the number of property names in `names`.
 *
 * Returns `0` if `names` is null.
 *
 * # Safety
 * `names` must be either null or a valid, live [`StatorPropertyNames`] pointer.
 */
size_t stator_property_names_count(const struct StatorPropertyNames *names);

/**
 * Return a pointer to the null-terminated property name at position `index`.
 *
 * The returned pointer is valid for as long as `names` is alive and has not
 * been destroyed.  Returns a null pointer if `names` is null or `index` is
 * out of range.
 *
 * # Safety
 * `names` must be either null or a valid, live [`StatorPropertyNames`] pointer.
 */
const char *stator_property_names_get(const struct StatorPropertyNames *names, size_t index);

/**
 * Destroy a [`StatorPropertyNames`] snapshot previously returned by
 * [`stator_object_get_property_names`].
 *
 * After this call the pointer and all name pointers obtained from it are
 * invalid and must not be used.
 *
 * # Safety
 * `names` must be a non-null pointer returned by
 * `stator_object_get_property_names` and must not be used again after this
 * call.
 */
void stator_property_names_destroy(struct StatorPropertyNames *names);

/**
 * Trigger a minor (young-generation) GC on the isolate heap.
 *
 * This is the preferred spelling for embedders using the Phase 1 object
 * model; it is equivalent to [`stator_isolate_gc`].
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
void stator_gc_collect(struct StatorIsolate *isolate);

/**
 * Return the number of live embedder-owned handles (values + objects) that
 * have been created on `isolate` but not yet destroyed.
 *
 * After a GC cycle this count reflects how many objects would survive because
 * they are still reachable through live handles.
 *
 * Returns 0 when `isolate` is null.
 *
 * # Safety
 * `isolate` must be either null or a valid, live [`StatorIsolate`] pointer.
 */
size_t stator_live_object_count(const struct StatorIsolate *isolate);

/**
 * Return the number of bytes currently allocated in the young-generation
 * from-space.  This is 0 immediately after a GC cycle.
 *
 * Returns 0 when `isolate` is null.
 *
 * # Safety
 * `isolate` must be either null or a valid, live [`StatorIsolate`] pointer.
 */
size_t stator_heap_used(const struct StatorIsolate *isolate);

/**
 * Return the total capacity (in bytes) of the young-generation semi-space,
 * counting both the from-space and to-space halves.
 *
 * Returns 0 when `isolate` is null.
 *
 * # Safety
 * `isolate` must be either null or a valid, live [`StatorIsolate`] pointer.
 */
size_t stator_heap_capacity(const struct StatorIsolate *isolate);

/**
 * Allocate a new owned [`StatorString`] from `len` UTF-8 bytes at `data`.
 *
 * Returns a non-null handle on success. When `data` is null and `len` is
 * zero, an empty string is returned. When `data` is null and `len` is
 * non-zero, returns null. The bytes are copied into engine-owned storage and
 * are not interpreted, validated, or required to be null-terminated.
 *
 * # Safety
 * - `data` must either be null (with `len == 0`) or point to at least `len`
 *   readable bytes for the duration of this call.
 */
struct StatorString *stator_string_new(const char *data, size_t len);

/**
 * Return a pointer to the UTF-8 bytes held by `string`.
 *
 * The returned pointer is valid for `stator_string_len(string)` bytes or until
 * `string` is freed, and is **not** guaranteed to be null-terminated. When the
 * length is zero, the pointer is only a zero-length buffer and must not be
 * dereferenced. Returns null when `string` is null.
 *
 * # Safety
 * - `string` must be either null or a valid pointer to a live
 *   [`StatorString`].
 */
const char *stator_string_data(const struct StatorString *string);

/**
 * Return the byte length of `string`.
 *
 * Returns `0` when `string` is null.
 *
 * # Safety
 * - `string` must be either null or a valid pointer to a live
 *   [`StatorString`].
 */
size_t stator_string_len(const struct StatorString *string);

/**
 * Free a [`StatorString`] previously returned by [`stator_string_new`] or
 * transferred from a host resolver to Stator.
 *
 * Passing null is a no-op.
 *
 * # Safety
 * - `string` must either be null or a pointer obtained from
 *   [`stator_string_new`] that has not already been freed.
 */
void stator_string_free(struct StatorString *string);

/**
 * Compile `source` (a UTF-8 string of `source_len` bytes) into bytecode.
 *
 * Returns a non-null [`StatorScript`] pointer in all cases (even on error).
 * Call [`stator_script_get_error`] to check whether compilation succeeded.
 * The caller must eventually pass the returned pointer to
 * [`stator_script_free`].
 *
 * Returns a null pointer only on an internal allocation failure (extremely
 * unlikely in practice).
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes. It must be
 *   valid UTF-8 except for WebAssembly modules, which must be binary Wasm.
 */
struct StatorScript *stator_script_compile(struct StatorContext *_ctx,
                                           const char *source,
                                           size_t source_len);

/**
 * Create an engine-owned classic-script code-cache blob for `script`.
 *
 * The returned [`StatorString`] owns a versioned cache blob containing
 * validation metadata (engine crate version, source hash/length, resource
 * name/offsets, and browser source metadata) plus serialized bytecode. On
 * success `out_telemetry`, when non-null, reports
 * [`StatorScriptCacheStatus::StatorScriptCacheStatusProducedMetadata`].
 *
 * # Safety
 * - `script` must be either null or a valid, live [`StatorScript`] pointer.
 * - `source` must be valid for reads of `source_len` bytes when non-null.
 * - `options`, when non-null, must point to readable compile options.
 * - `out_telemetry`, when non-null, must be valid for one telemetry write.
 */
struct StatorString *stator_script_create_code_cache(const struct StatorScript *script,
                                                     const char *source,
                                                     size_t source_len,
                                                     const struct StatorScriptCompileOptions *options,
                                                     struct StatorScriptCacheTelemetry *out_telemetry);

/**
 * Compile a classic script from `source` using a previously produced cache blob.
 *
 * The cache is accepted only when its magic, format version, engine crate
 * version, source length/hash, resource name, offsets, and source metadata
 * match. On a clean match Stator restores bytecode from the cache and reports
 * [`StatorScriptCacheStatus::StatorScriptCacheStatusAcceptedBytecodeRestored`].
 * Rejected, invalid, unsupported, or corrupt cache inputs never execute cached
 * bytes; Stator falls back to normal source compilation and reports the cache
 * status through `out_telemetry`.
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes.
 * - `cache_data` must be valid for reads of `cache_len` bytes.
 * - `options`, when non-null, must point to readable compile options.
 * - `out_telemetry`, when non-null, must be valid for one telemetry write.
 */
struct StatorScript *stator_script_compile_cached(struct StatorContext *ctx,
                                                  const char *source,
                                                  size_t source_len,
                                                  const char *cache_data,
                                                  size_t cache_len,
                                                  const struct StatorScriptCompileOptions *options,
                                                  struct StatorScriptCacheTelemetry *out_telemetry);

/**
 * Compile `source` (a UTF-8 string of `source_len` bytes) as a JavaScript ES module.
 *
 * This is equivalent to [`stator_module_compile_typed`] with
 * [`StatorModuleType::StatorModuleTypeJavaScript`].
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes of valid UTF-8.
 */
struct StatorModule *stator_module_compile(struct StatorContext *ctx,
                                           const char *source,
                                           size_t source_len);

/**
 * Compile `source` as a module with host-provided source kind metadata.
 *
 * JavaScript modules are parsed and compiled normally. JSON modules are parsed
 * and expose a `default` export. WebAssembly modules compile binary Wasm and
 * expose import-free function exports as callable named exports. CSS module
 * source kinds are recorded on the returned module handle but currently
 * produce an unsupported compile error because their evaluator is not
 * implemented in Stator yet.
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes. It must be
 *   valid UTF-8 except for WebAssembly modules, which must be binary Wasm.
 */
struct StatorModule *stator_module_compile_typed(struct StatorContext *ctx,
                                                 const char *source,
                                                 size_t source_len,
                                                 enum StatorModuleType source_type);

/**
 * Compile `source` as a module with stable source identity and policy options.
 *
 * This is the browser-oriented compile entry point for embedders that know the
 * module URL/resource name before compilation. `options` may be null, in which
 * case this is equivalent to [`stator_module_compile`]. When present, Stator
 * copies all option buffers and stores them on the returned module before it is
 * evaluated, so `import.meta.url`, resolver-origin metadata, and cache
 * validation all observe the same stable identity.
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes of valid UTF-8.
 * - `options`, when non-null, must point to a valid
 *   [`StatorModuleCompileOptions`] whose pointer/length pairs are readable
 *   when their lengths are non-zero.
 */
struct StatorModule *stator_module_compile_with_options(struct StatorContext *ctx,
                                                        const char *source,
                                                        size_t source_len,
                                                        const struct StatorModuleCompileOptions *options);

/**
 * Create an engine-owned module cache blob for `module` and `source`.
 *
 * The returned [`StatorString`] owns a versioned cache blob containing
 * validation metadata (engine crate version, source hash/length, module type,
 * resource name/offsets, and browser policy options) plus the compiled
 * bytecode/value/Wasm-byte payload and the module's static import/export
 * shape. On a successful production [`out_status`] is set to
 * [`StatorModuleCacheStatus::StatorModuleCacheStatusProducedMetadata`]; a
 * later [`stator_module_compile_cached`] call uses the blob to restore JS/JSON
 * modules without re-parsing or regenerating bytecode and to validate then
 * recompile WebAssembly modules from cached source bytes.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - `source` must be valid for reads of `source_len` bytes when non-null.
 * - `out_status`, when non-null, must be valid for one status write.
 */
struct StatorString *stator_module_create_code_cache(const struct StatorModule *module,
                                                     const char *source,
                                                     size_t source_len,
                                                     enum StatorModuleCacheStatus *out_status);

/**
 * Compile a module from `source` using a previously-produced cache blob.
 *
 * The cache is accepted only when its magic, format version, engine crate
 * version, source length/hash, module type, resource name, offsets, and
 * browser policy options all match. Malformed, stale, or incompatible blobs
 * fail closed by returning an errored [`StatorModule`] and reporting
 * [`StatorModuleCacheStatus::StatorModuleCacheStatusRejected`]. On a clean
 * JavaScript/JSON match Stator deserializes the module payload and reports
 * [`StatorModuleCacheStatus::StatorModuleCacheStatusAcceptedBytecodeRestored`].
 * On a clean WebAssembly match Stator validates the cached Wasm bytes and
 * parsed metadata, recompiles through Wasmtime, and reports
 * [`StatorModuleCacheStatus::StatorModuleCacheStatusAcceptedValidatedRecompiled`].
 * The returned module behaves identically to a freshly-compiled one for
 * linking, dynamic import, `import.meta.url`, live bindings, and TLA
 * fail-closed evaluation.
 *
 * # Safety
 * - `ctx` must be either null or a valid, live [`StatorContext`] pointer.
 * - `source` must be valid for reads of `source_len` bytes; it must be valid
 *   UTF-8 except for WebAssembly modules, which use binary Wasm bytes.
 * - `cache_data` must be valid for reads of `cache_len` bytes.
 * - `options`, when non-null, must point to readable compile options.
 * - `out_status`, when non-null, must be valid for one status write.
 */
struct StatorModule *stator_module_compile_cached(struct StatorContext *_ctx,
                                                  const char *source,
                                                  size_t source_len,
                                                  const char *cache_data,
                                                  size_t cache_len,
                                                  const struct StatorModuleCompileOptions *options,
                                                  enum StatorModuleCacheStatus *out_status);

/**
 * Return a null-terminated error message if `script` compiled with an error.
 *
 * Returns a null pointer when `script` compiled successfully.  The returned
 * pointer is valid as long as `script` is alive (i.e. until
 * [`stator_script_free`] is called).
 *
 * # Safety
 * `script` must be a non-null pointer returned by [`stator_script_compile`].
 */
const char *stator_script_get_error(const struct StatorScript *script);

/**
 * Attach origin metadata (resource name and offsets) to `script`.
 *
 * Mirrors the embedder-side construction of `v8::ScriptOrigin`.  The
 * metadata is stored on the script and is intended to be surfaced through
 * future stack-trace and error-reporting APIs; today it is plumbing only.
 *
 * `resource_name` may be null to clear an existing name; otherwise it must
 * be a valid, null-terminated UTF-8 C string.  The contents are copied; the
 * caller retains ownership of the input buffer.
 *
 * Does nothing when `script` is null.
 *
 * # Safety
 * - `script` must be either null or a valid, live [`StatorScript`] pointer.
 * - When non-null, `resource_name` must be a valid, null-terminated UTF-8
 *   C string.
 */
void stator_script_set_origin(struct StatorScript *script,
                              const char *resource_name,
                              int32_t line_offset,
                              int32_t column_offset);

/**
 * Return the resource name previously set on `script`, or null if none has
 * been set.
 *
 * The returned pointer is valid as long as `script` is alive (i.e. until
 * [`stator_script_free`] is called) and as long as the origin is not
 * overwritten by another call to [`stator_script_set_origin`].
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
const char *stator_script_get_resource_name(const struct StatorScript *script);

/**
 * Return the line offset previously set on `script` (default 0).
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
int32_t stator_script_get_line_offset(const struct StatorScript *script);

/**
 * Return the column offset previously set on `script` (default 0).
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
int32_t stator_script_get_column_offset(const struct StatorScript *script);

/**
 * Print the decoded bytecode listing for `script` to standard output.
 *
 * Each instruction is printed on a new line in the form:
 * `  <OpcodeName> [<operand>, …]`
 *
 * Does nothing if `script` is null or compiled with an error.
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
void stator_bytecode_dump(const struct StatorScript *script);

/**
 * Return the number of bytecode instructions in a successfully compiled script.
 *
 * Returns 0 if `script` is null, compiled with an error, or the bytecode
 * stream cannot be decoded.
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
size_t stator_script_bytecode_count(const struct StatorScript *script);

/**
 * Fill `*status` with tiering state for `script`.
 *
 * Returns `false` when either pointer is null or the script failed to compile.
 *
 * # Safety
 * - `script` must be null or a valid, live `StatorScript` pointer.
 * - `status` must be null or valid for writes.
 */
bool stator_script_get_tier_status(const struct StatorScript *script,
                                   struct StatorScriptTierStatus *status);

/**
 * Synchronously force Maglev compilation for `script` when the platform supports it.
 *
 * Returns `false` for null/failed scripts and on unsupported platforms.
 *
 * # Safety
 * `script` must be null or a valid, live `StatorScript` pointer.
 */
bool stator_script_force_maglev_compile(struct StatorScript *script);

/**
 * Synchronously request compilation of `tier` for `script`.
 *
 * Returns `true` only when the requested tier is observable as ready after the
 * call. `*result` is always filled for non-null pointers and reports
 * unsupported tiers, disabled JIT, and compile failures without faking success.
 *
 * # Safety
 * - `script` must be null or a valid, live `StatorScript` pointer.
 * - `result` must be null or valid for writes.
 */
bool stator_script_force_tier(struct StatorScript *script,
                              enum StatorJitTier tier,
                              struct StatorTierRequestResult *result);

/**
 * Observe whether `tier` is currently ready for `script` without compiling.
 *
 * # Safety
 * - `script` must be null or a valid, live `StatorScript` pointer.
 * - `result` must be null or valid for writes.
 */
bool stator_script_observe_tier(const struct StatorScript *script,
                                enum StatorJitTier tier,
                                struct StatorTierRequestResult *result);

/**
 * Wait up to `timeout_ms` for `tier` to become ready for `script`.
 *
 * Returns `true` only when the tier becomes observable as ready.
 *
 * # Safety
 * - `script` must be null or a valid, live `StatorScript` pointer.
 * - `result` must be null or valid for writes.
 */
bool stator_script_wait_for_tier(const struct StatorScript *script,
                                 enum StatorJitTier tier,
                                 uint64_t timeout_ms,
                                 struct StatorTierRequestResult *result);

/**
 * Disable Maglev/Turbofan tier-up for a compiled script.
 *
 * This is intended for embedders that need deterministic interpreter
 * execution for workloads whose JIT tier is known to be unstable.
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
void stator_script_disable_jit(struct StatorScript *script);

/**
 * Reset JIT deopt backoff state for a compiled script.
 *
 * This lets embedders perform a warmup phase, clear transient first-run deopts,
 * and then measure or execute with warmed inline caches. It does not discard
 * compiled JIT code.
 *
 * # Safety
 * `script` must be either null or a valid, live [`StatorScript`] pointer.
 */
void stator_script_reset_jit_deopts(struct StatorScript *script);

/**
 * Free a [`StatorScript`] previously returned by [`stator_script_compile`].
 *
 * # Safety
 * `script` must be a non-null pointer returned by [`stator_script_compile`]
 * and must not be used again after this call.
 */
void stator_script_free(struct StatorScript *script);

/**
 * Return a null-terminated error message if `module` compiled with an error.
 *
 * Returns a null pointer when `module` compiled successfully. The returned
 * pointer is valid as long as `module` is alive.
 *
 * # Safety
 * `module` must be a non-null pointer returned by [`stator_module_compile`].
 */
const char *stator_module_get_error(const struct StatorModule *module);

/**
 * Return the structured [`StatorMessageKind`] of `module`'s compile error.
 *
 * Returns [`StatorMessageKind::StatorMessageKindUnknown`] when `module`
 * compiled successfully or is null.
 *
 * # Safety
 * `module` must be either null or a valid pointer to a live [`StatorModule`].
 */
enum StatorMessageKind stator_module_error_kind(const struct StatorModule *module);

/**
 * Report whether Stator can compile and evaluate modules of `source_type`
 * itself without host integration.
 *
 * Returns `true` for [`StatorModuleType::StatorModuleTypeJavaScript`],
 * [`StatorModuleType::StatorModuleTypeJson`], and
 * [`StatorModuleType::StatorModuleTypeWebAssembly`].
 *
 * Returns `false` for typed module kinds that Stator recognises but cannot
 * execute on its own — currently only [`StatorModuleType::StatorModuleTypeCss`],
 * which has no engine-side parser or `CSSStyleSheet` representation.
 * Attempting to compile, evaluate, or restore from a code cache for such a
 * type always fails closed: [`stator_module_compile`] returns an errored
 * module whose [`stator_module_error_kind`] is
 * [`StatorMessageKind::StatorMessageKindUnsupportedModuleType`], and
 * [`stator_module_compile_cached`] additionally sets the cache status to
 * [`StatorModuleCacheStatus::StatorModuleCacheStatusUnsupported`].
 *
 * Embedders like the Edge host can call this before compiling to route an
 * import through host integration (e.g. a `CSSStyleSheet` provider) instead
 * of asking the engine to compile something it cannot execute.
 *
 * Unknown / future values of `source_type` are treated as not executable.
 */
bool stator_module_type_is_executable(enum StatorModuleType source_type);

/**
 * Attach origin metadata (resource name and offsets) to `module`.
 *
 * `resource_name` may be null to clear an existing name; otherwise it must be
 * a valid, null-terminated UTF-8 C string. The contents are copied.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - When non-null, `resource_name` must be a valid, null-terminated UTF-8
 *   C string.
 */
void stator_module_set_origin(struct StatorModule *module,
                              const char *resource_name,
                              int32_t line_offset,
                              int32_t column_offset);

/**
 * Return the resource name previously set on `module`, or null if none.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
const char *stator_module_get_resource_name(const struct StatorModule *module);

/**
 * Return the line offset previously set on `module` (default 0).
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
int32_t stator_module_get_line_offset(const struct StatorModule *module);

/**
 * Return the column offset previously set on `module` (default 0).
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
int32_t stator_module_get_column_offset(const struct StatorModule *module);

/**
 * Attach browser policy/origin metadata to `module`.
 *
 * Records the embedder's per-module-fetch context — base URL, Subresource
 * Integrity metadata, credentials mode, referrer policy, and parser metadata
 * — so that the host module resolver can apply same-origin, CORS, COEP, CSP
 * `script-src`, integrity, referrer-policy, and parser-metadata checks before
 * returning a resolved module from a static `import`, re-export, or
 * `import`-with-attributes request.
 *
 * Strings (`base_url`, `integrity_metadata`) are copied into `module`; the
 * caller retains ownership of the input buffers and may free them as soon as
 * this call returns. The stored copies remain stable until either
 * [`stator_module_set_origin_metadata`] is called again or the module is
 * freed by [`stator_module_free`].
 *
 * `base_url` / `integrity_metadata` may be null when the corresponding
 * length is zero to clear that field. Passing a null pointer with a non-zero
 * length is rejected as invalid input: the call returns `false` and the
 * previously stored metadata on `module` is preserved unchanged.
 *
 * Returns `true` on success, `false` when `module` is null or when any
 * pointer/length pair is inconsistent.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - When `base_url_len > 0`, `base_url` must be valid for reads of
 *   `base_url_len` bytes.
 * - When `integrity_metadata_len > 0`, `integrity_metadata` must be valid
 *   for reads of `integrity_metadata_len` bytes.
 */
bool stator_module_set_origin_metadata(struct StatorModule *module,
                                       const char *base_url,
                                       size_t base_url_len,
                                       enum StatorCredentialsMode credentials_mode,
                                       const char *integrity_metadata,
                                       size_t integrity_metadata_len,
                                       enum StatorReferrerPolicy referrer_policy,
                                       enum StatorParserMetadata parser_metadata);

/**
 * Attach source/cache metadata v2 to `module`.
 *
 * The metadata's `source_type` must match the compiled module type. Pointer
 * fields with non-zero lengths must be non-null. On failure the existing
 * metadata is preserved, so cache identity never silently drops a supplied
 * field.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - `metadata`, when non-null, must point to a readable
 *   [`StatorModuleSourceMetadataV2`].
 * - Every non-null metadata pointer must be valid for its paired length.
 */
bool stator_module_set_source_metadata_v2(struct StatorModule *module,
                                          const struct StatorModuleSourceMetadataV2 *metadata);

/**
 * Query source/cache metadata v2 currently stored on `module`.
 *
 * Borrowed pointers written into `out_metadata` remain valid until the module
 * is freed or its metadata is overwritten.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - `out_metadata` must be valid for one struct write.
 */
bool stator_module_get_source_metadata_v2(const struct StatorModule *module,
                                          struct StatorModuleSourceMetadataV2 *out_metadata);

/**
 * Return a pointer to the base-URL bytes previously set on `module`, or null
 * when no base URL is set.
 *
 * `out_len`, when non-null, receives the byte length of the base URL (zero
 * when the return value is null). The bytes are not null-terminated and are
 * valid as long as `module` is alive and the metadata is not overwritten by
 * another call to [`stator_module_set_origin_metadata`].
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - `out_len`, when non-null, must be valid for one `usize` write.
 */
const char *stator_module_get_base_url(const struct StatorModule *module, size_t *out_len);

/**
 * Return a pointer to the integrity-metadata bytes previously set on
 * `module`, or null when none is set.
 *
 * `out_len`, when non-null, receives the byte length (zero when the return
 * value is null). The bytes are not null-terminated and are valid as long as
 * `module` is alive and the metadata is not overwritten by another call to
 * [`stator_module_set_origin_metadata`].
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - `out_len`, when non-null, must be valid for one `usize` write.
 */
const char *stator_module_get_integrity_metadata(const struct StatorModule *module,
                                                 size_t *out_len);

/**
 * Return the credentials mode previously set on `module`, or
 * [`StatorCredentialsMode::StatorCredentialsModeDefault`] when unset.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
enum StatorCredentialsMode stator_module_get_credentials_mode(const struct StatorModule *module);

/**
 * Return the referrer policy previously set on `module`, or
 * [`StatorReferrerPolicy::StatorReferrerPolicyDefault`] when unset.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
enum StatorReferrerPolicy stator_module_get_referrer_policy(const struct StatorModule *module);

/**
 * Return the parser-metadata classification previously set on `module`, or
 * [`StatorParserMetadata::StatorParserMetadataNotParserInserted`] when unset.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
enum StatorParserMetadata stator_module_get_parser_metadata(const struct StatorModule *module);

/**
 * Return the number of bytecode instructions in a compiled module.
 *
 * Returns 0 if `module` is null, failed to compile, or cannot be decoded.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
size_t stator_module_bytecode_count(const struct StatorModule *module);

/**
 * Return whether the compiled module bytecode is marked as async.
 *
 * Modules are compiled with async capability so hosts can later drive
 * top-level-await evaluation. Returns false for null or failed modules.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
bool stator_module_is_async(const struct StatorModule *module);

/**
 * Return whether `module` contains static imports or re-exports.
 *
 * Dependency-bearing modules require a host resolver/linker before this FFI
 * layer can safely evaluate them. Dependency-free modules can be evaluated by
 * [`stator_module_evaluate`].
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
bool stator_module_has_dependencies(const struct StatorModule *module);

/**
 * Return the number of static import/re-export requests in `module`.
 *
 * Requests are reported in source order. Returns 0 for null or failed modules.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
size_t stator_module_get_request_count(const struct StatorModule *module);

/**
 * Return one static module request's specifier and import attributes.
 *
 * All out-pointers are optional. Returned pointers are borrowed from `module`
 * and remain valid until [`stator_module_free`] or recompilation of a future
 * replacement handle. The specifier is not null-terminated; use
 * `out_specifier_len`.
 *
 * Returns `false` when `module` is null or `idx` is out of range.
 *
 * # Safety
 * - `module` must be either null or a valid, live [`StatorModule`] pointer.
 * - Each non-null out-pointer must be valid for one pointer/length write.
 */
bool stator_module_get_request(const struct StatorModule *module,
                               size_t idx,
                               const char **out_specifier,
                               size_t *out_specifier_len,
                               const struct StatorImportAttribute **out_attributes,
                               size_t *out_attributes_len);

/**
 * Return the current link/evaluation status for `module`.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
enum StatorModuleStatus stator_module_get_status(const struct StatorModule *module);

/**
 * Return the source kind metadata recorded on `module`.
 *
 * Null module pointers report JavaScript so embedders can treat legacy/default
 * paths as JavaScript-compatible.
 *
 * # Safety
 * `module` must be either null or a valid, live [`StatorModule`] pointer.
 */
enum StatorModuleType stator_module_get_type(const struct StatorModule *module);

/**
 * Retain a module record and return a fail-closed handle for later queries.
 *
 * The returned handle keeps `module` alive even if the embedder subsequently
 * calls [`stator_module_free`] on the raw module pointer. Release it with
 * [`stator_module_handle_release`] and then destroy the handle with
 * [`stator_module_handle_destroy`].
 *
 * # Safety
 * `module` must be null or a valid, live [`StatorModule`] pointer.
 */
struct StatorModuleHandle *stator_module_retain(struct StatorModule *module);

/**
 * Return whether a retained module handle still refers to a live module.
 *
 * # Safety
 * `handle` must be null or a pointer returned by [`stator_module_retain`].
 */
bool stator_module_handle_is_valid(const struct StatorModuleHandle *handle);

/**
 * Return the retained raw module pointer, or null for a stale handle.
 *
 * # Safety
 * `handle` must be null or a pointer returned by [`stator_module_retain`].
 */
struct StatorModule *stator_module_handle_get_module(const struct StatorModuleHandle *handle);

/**
 * Query a retained module handle's current status.
 *
 * Stale handles fail closed as [`StatorModuleStatus::StatorModuleStatusErrored`].
 *
 * # Safety
 * `handle` must be null or a pointer returned by [`stator_module_retain`].
 */
enum StatorModuleStatus stator_module_handle_get_status(const struct StatorModuleHandle *handle);

/**
 * Release the module record retained by `handle`.
 *
 * The handle remains allocated as a stale tombstone so subsequent queries fail
 * closed. Call [`stator_module_handle_destroy`] to free the handle storage.
 *
 * # Safety
 * `handle` must be null or a pointer returned by [`stator_module_retain`].
 */
bool stator_module_handle_release(struct StatorModuleHandle *handle);

/**
 * Destroy a retained module handle.
 *
 * If the handle was not released yet, this releases it first.
 *
 * # Safety
 * `handle` must be null or a pointer returned by [`stator_module_retain`] and
 * must not be used again after this call.
 */
void stator_module_handle_destroy(struct StatorModuleHandle *handle);

/**
 * Resolve and consume a dynamic-import request with a compiled module.
 *
 * Stator instantiates and evaluates `module` using the request's original
 * context, then fulfils the JavaScript promise with the module namespace object
 * placeholder used by the current module runtime. On failure the promise is
 * rejected with the structured module error and the request is still consumed.
 *
 * # Safety
 * - `request` must be a live request accepted by the host dynamic-import
 *   callback and not previously settled.
 * - `module` must be null or a live compiled module pointer. Null rejects with
 *   `StatorResolveStatusNotFound`.
 * - Must be called on the same serialized context/module thread as the
 *   callback.
 */
enum StatorResolveStatus stator_dynamic_import_request_resolve_module(struct StatorDynamicImportRequest *request,
                                                                      struct StatorModule *module);

/**
 * Reject and consume a dynamic-import request with a structured host error.
 *
 * `detail`, when non-null, must be a [`StatorString`] allocated by
 * [`stator_string_new`]; ownership transfers to Stator.
 *
 * # Safety
 * `request` must be a live request accepted by the host dynamic-import
 * callback and not previously settled. Must be called on the same serialized
 * context/module thread as the callback.
 */
bool stator_dynamic_import_request_reject(struct StatorDynamicImportRequest *request,
                                          enum StatorResolveStatus status,
                                          struct StatorString *detail);

/**
 * Reject and consume a dynamic-import request that the host abandons.
 *
 * # Safety
 * `request` must be a live request accepted by the host dynamic-import
 * callback and not previously settled.
 */
bool stator_dynamic_import_request_dispose(struct StatorDynamicImportRequest *request);

/**
 * Query source/cache metadata carried by a dynamic import request.
 *
 * The returned pointers borrow from the request and remain valid until the
 * request is resolved, rejected, or disposed.
 *
 * # Safety
 * - `request` must be either null or a live [`StatorDynamicImportRequest`].
 * - `out_metadata` must be valid for one struct write.
 */
bool stator_dynamic_import_request_get_source_metadata_v2(const struct StatorDynamicImportRequest *request,
                                                          struct StatorModuleSourceMetadataV2 *out_metadata);

/**
 * Link a compiled module graph by resolving all static import/re-export requests.
 *
 * Dependency-free modules transition to `Linked` without a context. Modules
 * with requests require a resolver registered on `ctx`; the resolver is invoked
 * depth-first and cycles are accepted without infinite recursion. This slice
 * validates graph availability only: evaluation of dependency-bearing modules
 * still returns an explicit error until live binding wiring lands.
 *
 * Returns `true` on successful graph instantiation. On failure returns `false`
 * and stores an error on the root module.
 *
 * # Safety
 * - `module` must be a non-null pointer returned by [`stator_module_compile`].
 * - `ctx` must be null only for dependency-free modules, or a valid live
 *   [`StatorContext`] pointer for modules with requests.
 */
bool stator_module_instantiate(struct StatorContext *ctx, struct StatorModule *module);

/**
 * Link and evaluate a compiled module.
 *
 * This module-runtime slice drives the module record through
 * `Unlinked -> Linking -> Linked -> Evaluating -> Evaluated`. On success it
 * returns the top-level completion value as a new [`StatorValue`]. On failure
 * it returns null, stores the error on `module`, and publishes a pending
 * exception on `ctx` when a context is supplied.
 *
 * For linked module graphs, dependencies are evaluated depth-first and simple
 * named/default import cells are copied from dependency exports before the
 * importing module runs. Namespace objects and TLA remain incomplete.
 *
 * # Safety
 * - `module` must be a non-null pointer returned by [`stator_module_compile`].
 * - `ctx` must be a valid, live [`StatorContext`] pointer, or null (in which
 *   case an empty global environment is used).
 */
struct StatorValue *stator_module_evaluate(struct StatorModule *module, struct StatorContext *ctx);

/**
 * Free a [`StatorModule`] previously returned by [`stator_module_compile`].
 *
 * # Safety
 * `module` must be a non-null pointer returned by [`stator_module_compile`]
 * and must not be used again after this call.
 */
void stator_module_free(struct StatorModule *module);

/**
 * Returns `true` if `module` is currently parked on an unresolved
 * top-level `await`, i.e. its status is
 * [`StatorModuleStatus::StatorModuleStatusPendingAsyncEvaluation`].
 *
 * This is a pure status query and does not advance evaluation.
 *
 * # Safety
 * `module` must be a non-null pointer returned by [`stator_module_compile`].
 */
bool stator_module_evaluation_is_pending(struct StatorModule *module);

/**
 * Drive a parked top-level-await module forward without changing the
 * settlement state of its awaited promise. Use this after the embedder
 * has settled the awaited promise via some external mechanism (e.g. a
 * chained `then`/`resolve` performed through ordinary script execution),
 * or simply to allow queued microtasks to drain and re-check the parked
 * promise.
 *
 * Returns:
 * - a fresh [`StatorValue`] (caller must free with [`stator_value_free`])
 *   when the module body completes;
 * - null when the body parks again on another await (module status stays
 *   [`StatorModuleStatus::StatorModuleStatusPendingAsyncEvaluation`]) or
 *   when evaluation fails (in which case the module's `error` is set and
 *   a pending exception is published on `ctx`).
 *
 * # Safety
 * - `module` must be a non-null pointer returned by
 *   [`stator_module_compile`] whose status is
 *   [`StatorModuleStatus::StatorModuleStatusPendingAsyncEvaluation`].
 * - `ctx` may be null; when non-null it must be a live [`StatorContext`].
 */
struct StatorValue *stator_module_resume_evaluation(struct StatorModule *module,
                                                    struct StatorContext *ctx);

/**
 * Fulfil the promise the module body is awaiting with `value` and then
 * drive evaluation forward.
 *
 * `value` may be null, which is treated as `undefined`. The value is
 * copied into the engine; ownership of `value` is retained by the caller.
 *
 * Return value and status transitions mirror
 * [`stator_module_resume_evaluation`].
 *
 * # Safety
 * - `module` must be a non-null pointer returned by
 *   [`stator_module_compile`] whose status is
 *   [`StatorModuleStatus::StatorModuleStatusPendingAsyncEvaluation`].
 * - `ctx` may be null; when non-null it must be a live [`StatorContext`].
 * - `value` may be null or a pointer returned by any `stator_value_*`
 *   constructor; it remains owned by the caller.
 */
struct StatorValue *stator_module_pending_evaluation_fulfill(struct StatorModule *module,
                                                             struct StatorContext *ctx,
                                                             struct StatorValue *value);

/**
 * Reject the promise the module body is awaiting with `reason` and then
 * drive evaluation forward. The rejection is thrown back into the module
 * body where a surrounding `try { await … } catch { … }` may observe it;
 * an uncaught rejection completes evaluation as `Errored`.
 *
 * `reason` may be null, which is treated as `undefined`. The value is
 * copied into the engine; ownership of `reason` is retained by the caller.
 *
 * Return value and status transitions mirror
 * [`stator_module_resume_evaluation`].
 *
 * # Safety
 * - `module` must be a non-null pointer returned by
 *   [`stator_module_compile`] whose status is
 *   [`StatorModuleStatus::StatorModuleStatusPendingAsyncEvaluation`].
 * - `ctx` may be null; when non-null it must be a live [`StatorContext`].
 * - `reason` may be null or a pointer returned by any `stator_value_*`
 *   constructor; it remains owned by the caller.
 */
struct StatorValue *stator_module_pending_evaluation_reject(struct StatorModule *module,
                                                            struct StatorContext *ctx,
                                                            struct StatorValue *reason);

/**
 * Execute a compiled script in `ctx` and return the result as a
 * [`StatorValue`].
 *
 * The script must have been successfully compiled (i.e.
 * [`stator_script_get_error`] returns null).  If the script produces an
 * exception the call returns null.
 *
 * The caller must pass the returned pointer to [`stator_value_destroy`] when
 * done, or ignore a null return.
 *
 * # Safety
 * - `script` must be a non-null pointer returned by [`stator_script_compile`].
 * - `ctx` must be a valid, live [`StatorContext`] pointer, or null (in which
 *   case an empty global environment is used).
 */
struct StatorValue *stator_script_run(const struct StatorScript *script, struct StatorContext *ctx);

/**
 * Execute a compiled script in `ctx` and discard the result.
 *
 * Returns `true` when execution completes without an exception.  This avoids
 * allocating an embedder-owned [`StatorValue`] for callers that only need to
 * drive script execution and do not inspect the result.
 *
 * # Safety
 * - `script` must be a non-null pointer returned by [`stator_script_compile`].
 * - `ctx` must be a valid, live [`StatorContext`] pointer, or null (in which
 *   case an empty global environment is used).
 */
bool stator_script_run_no_result(const struct StatorScript *script, struct StatorContext *ctx);

/**
 * Convert the value `val` to a UTF-8 string and write it into `buf`.
 *
 * At most `buf_len` bytes (including the NUL terminator) are written.
 * Returns the number of bytes written **excluding** the NUL terminator, or
 * `-1` on error.  Returns `0` when `val` is null (writes `""` and a NUL).
 *
 * # Safety
 * - `val` must be either null or a valid, live [`StatorValue`] pointer.
 * - `buf` must be valid for writes of `buf_len` bytes, or null when
 *   `buf_len` is 0 (in which case only the required length is returned).
 */
int32_t stator_value_to_string_utf8(const struct StatorValue *val, char *buf, size_t buf_len);

/**
 * Coerce `val` to a number following ECMAScript §7.1.4 **ToNumber**.
 *
 * | Value type | Result |
 * |---|---|
 * | `undefined` (or null pointer) | `NaN` |
 * | `null` | `+0` |
 * | `true` | `1` |
 * | `false` | `+0` |
 * | number | the number itself |
 * | string | parsed numeric value; `NaN` if unparseable |
 * | object / function / … | `NaN` |
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
double stator_value_to_number(const struct StatorValue *val);

/**
 * Coerce `val` to a string following ECMAScript §7.1.17 **ToString** and
 * return it as a new [`StatorValue`] of string type.
 *
 * The caller owns the returned pointer and must pass it to
 * [`stator_value_destroy`] (or let a handle scope manage it).
 *
 * Returns a null pointer if `isolate` is null.
 *
 * # Safety
 * - `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 * - `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
struct StatorValue *stator_value_to_string(struct StatorIsolate *isolate,
                                           const struct StatorValue *val);

/**
 * Coerce `val` to a signed 32-bit integer following ECMAScript §7.1.7
 * **ToInt32**.
 *
 * Applies `ToNumber` first, then reduces modulo 2³² and maps to the signed
 * range `[−2³¹, 2³¹−1]`.  `NaN`, `±0`, and `±Infinity` all convert to `0`.
 *
 * Returns `0` when `val` is null.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
int32_t stator_value_to_int32(const struct StatorValue *val);

/**
 * Coerce `val` to an unsigned 32-bit integer following ECMAScript §7.1.8
 * **ToUint32**.
 *
 * Applies `ToNumber` first, then reduces modulo 2³².  `NaN`, `±0`, and
 * `±Infinity` all convert to `0`.
 *
 * Returns `0` when `val` is null.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
uint32_t stator_value_to_uint32(const struct StatorValue *val);

/**
 * Coerce `val` to a boolean following ECMAScript §7.1.2 **ToBoolean**.
 *
 * Falsy values: `undefined`, `null`, `false`, `+0`, `-0`, `NaN`, `""`.
 * Everything else is truthy.  A null pointer is treated as `undefined` and
 * returns `false`.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
bool stator_value_to_boolean(const struct StatorValue *val);

/**
 * Test whether `a === b` following ECMAScript §7.2.15 **IsStrictlyEqual**.
 *
 * Rules:
 * - Different types → `false`.
 * - `undefined === undefined` → `true`.
 * - `null === null` → `true`.
 * - Numbers: `NaN !== NaN`; `+0 === -0`.
 * - Strings: byte-for-byte equality.
 * - Booleans: value equality.
 * - Tag-only object / function / array / promise placeholders: `false`
 *   because they carry no shared identity in FFI handles.
 * - Shared-storage object, DOM wrapper, and Promise handles: identity equality
 *   based on the underlying shared engine handle.
 *
 * Both null pointers are treated as `undefined`.
 *
 * # Safety
 * `a` and `b` must each be either null or a valid, live [`StatorValue`]
 * pointer.
 */
bool stator_value_strict_equals(const struct StatorValue *a, const struct StatorValue *b);

/**
 * Read the boolean value of `val` into `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when `val` holds a JavaScript boolean.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but not a
 *   boolean.  `*out` is left untouched.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `out` is null.
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `out` must be either null or a valid pointer to a `bool`.
 */
enum StatorStatus stator_value_get_boolean(const struct StatorValue *val, bool *out);

/**
 * Read the numeric value of `val` into `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when `val` holds a JavaScript number.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but not a
 *   number.  `*out` is left untouched.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `out` is null.
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `out` must be either null or a valid pointer to an `f64`.
 */
enum StatorStatus stator_value_get_number(const struct StatorValue *val, double *out);

/**
 * Read `val` as a signed 32-bit integer into `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when `val` is a finite integer in the
 *   range `[−2³¹, 2³¹−1]`; `*out` is set to the exact value.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but is not
 *   exactly representable as an `i32` (non-number, fractional, ±Infinity,
 *   `NaN`, or out of range).  `*out` is left untouched.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `out` is null.
 *
 * Mirrors the semantics of `v8::Value::Int32Value` for the success case but
 * without the implicit `ToNumber` coercion — embedders that want the lossy
 * truncating conversion should call [`stator_value_to_int32`] instead.
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `out` must be either null or a valid pointer to an `i32`.
 */
enum StatorStatus stator_value_get_int32(const struct StatorValue *val, int32_t *out);

/**
 * Read `val` as an unsigned 32-bit integer into `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when `val` is a finite integer in the
 *   range `[0, 2³²−1]`; `*out` is set to the exact value.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but is not
 *   exactly representable as a `u32`.  `*out` is left untouched.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `out` is null.
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `out` must be either null or a valid pointer to a `u32`.
 */
enum StatorStatus stator_value_get_uint32(const struct StatorValue *val, uint32_t *out);

/**
 * Read the UTF-8 byte length of the string stored in `val` into `*out`.
 *
 * The returned length does **not** include a terminating null byte and is
 * the count of raw UTF-8 bytes — sufficient for sizing a buffer passed to
 * [`stator_value_write_string_utf8`].
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when `val` is a string; `*out` is the
 *   byte length.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but not a
 *   string.  `*out` is left untouched.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `out` is null.
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `out` must be either null or a valid pointer to a `usize`.
 */
enum StatorStatus stator_value_get_string_utf8_length(const struct StatorValue *val, size_t *out);

/**
 * Copy the UTF-8 representation of the string stored in `val` into `buf`.
 *
 * The write APIs work in explicit byte counts: no implicit `strlen` is
 * performed on the source side and no terminating null byte is appended to
 * the destination.  This makes the API safe to use with input data that
 * contains, or buffers that should accommodate, embedded NUL bytes.
 *
 * At most `buf_size` bytes are written.  If `buf_size` is smaller than the
 * string's byte length the output is truncated; callers can size their
 * buffer with [`stator_value_get_string_utf8_length`] and inspect
 * `*written` to detect truncation.
 *
 * On success, `*written` (if non-null) is set to the number of bytes
 * actually written.  On any non-OK return `*written` is set to zero so
 * callers never see stale length information.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] on a (possibly truncated) successful
 *   write.
 * * [`StatorStatus::StatorStatusFalse`] when `val` is non-null but not a
 *   string.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `val` or `buf` is null.
 *   A null `written` pointer is allowed (and simply discards the length).
 *
 * # Safety
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 * * `buf` must be valid for writes of `buf_size` bytes (unless null).
 * * `written` must be either null or a valid pointer to a `usize`.
 */
enum StatorStatus stator_value_write_string_utf8(const struct StatorValue *val,
                                                 char *buf,
                                                 size_t buf_size,
                                                 size_t *written);

/**
 * Wrap a [`StatorObject`] handle as a fresh [`StatorValue`] handle that
 * shares the same underlying `PropertyMap` storage.
 *
 * The returned value's `typeof` is `"object"`; passing it to
 * [`stator_value_as_object`] yields a new [`StatorObject`] handle whose
 * property mutations are observed through `obj` and vice versa.  This is
 * the FFI mechanism for round-tripping object identity across the
 * value/object boundary.
 *
 * Returns a null pointer when `obj` is null.  The caller owns the returned
 * value pointer and must release it with [`stator_value_destroy`] (or rely
 * on the active handle scope).
 *
 * # Safety
 * `obj` must be either null or a valid, live [`StatorObject`] pointer.
 */
struct StatorValue *stator_object_as_value(const struct StatorObject *obj);

/**
 * Wrap a [`StatorValue`] holding an object-as-value handle as a fresh
 * [`StatorObject`] handle that shares the same underlying `JsObject`
 * storage.
 *
 * Identity is only preserved for values produced by
 * [`stator_object_as_value`] (or by future FFI APIs that allocate the
 * shared-storage representation).  Tag-only object values created via
 * [`stator_value_new_object`], `stator_value_new_array_tag`, and the other
 * tag constructors carry no per-instance storage; passing such a value
 * here returns a null pointer to make the limitation explicit at the call
 * site rather than silently materialising a divergent empty object.
 *
 * Returns a null pointer when `val` is null, is not an object-like value,
 * or is a tag-only object value.  The caller owns the returned object
 * pointer and must release it with [`stator_object_destroy`].
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
struct StatorObject *stator_value_as_object(const struct StatorValue *val);

/**
 * Read the property named `(key, key_len)` from `obj` and, on success, write
 * a freshly-allocated [`StatorValue`] handle to `*out_val`.
 *
 * Maybe-style semantics:
 * * [`StatorStatus::StatorStatusOk`] when the property exists.  The
 *   returned value mirrors the property value, including an explicit
 *   `undefined` if that is what is stored.
 * * [`StatorStatus::StatorStatusFalse`] when the property is missing from
 *   `obj` and its prototype chain.  `*out_val` is set to null.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `obj`, `key`, or
 *   `out_val` is null, when the key bytes are not valid UTF-8, or when the
 *   object has no associated isolate.
 *
 * The caller owns the [`StatorValue`] handed back through `*out_val` and
 * must release it with [`stator_value_destroy`] (or rely on the active
 * handle scope).
 *
 * # Safety
 * * `obj` must be either null or a valid, live [`StatorObject`] pointer.
 * * `key` must be valid for reads of `key_len` bytes (or null).
 * * `out_val` must be either null or a valid pointer to a `*mut StatorValue`.
 */
enum StatorStatus stator_object_get_property(const struct StatorObject *obj,
                                             const char *key,
                                             size_t key_len,
                                             struct StatorValue **out_val);

/**
 * Write `val` to the property named `(key, key_len)` on `obj`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when the property was created or
 *   updated.
 * * [`StatorStatus::StatorStatusException`] when the underlying `[[Set]]`
 *   raised an error (e.g. assigning to a read-only property).  The
 *   isolate's pending exception is populated with a stringified error and
 *   a structured [`StatorMessage`] classified as
 *   [`StatorMessageKind::StatorMessageKindType`].
 * * [`StatorStatus::StatorStatusInvalidArg`] when `obj`, `key`, or `val` is
 *   null, when the key bytes are not valid UTF-8, or when the object has
 *   no associated isolate.
 *
 * # Safety
 * * `obj` must be either null or a valid, live [`StatorObject`] pointer.
 * * `key` must be valid for reads of `key_len` bytes (or null).
 * * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
enum StatorStatus stator_object_set_property(struct StatorObject *obj,
                                             const char *key,
                                             size_t key_len,
                                             const struct StatorValue *val);

/**
 * Test whether `obj` has a property named `(key, key_len)` (own or
 * inherited).  The result is written to `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] on success; `*out` is `true` iff the
 *   property exists.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `obj`, `key`, or `out` is
 *   null, or when the key bytes are not valid UTF-8.
 *
 * # Safety
 * * `obj` must be either null or a valid, live [`StatorObject`] pointer.
 * * `key` must be valid for reads of `key_len` bytes (or null).
 * * `out` must be either null or a valid pointer to a `bool`.
 */
enum StatorStatus stator_object_has_property(const struct StatorObject *obj,
                                             const char *key,
                                             size_t key_len,
                                             bool *out);

/**
 * Delete the property named `(key, key_len)` from `obj`.  The boolean
 * outcome of the underlying `[[Delete]]` is written to `*out`.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] on success.  `*out` is `true` when
 *   the property no longer exists (either it was successfully deleted or
 *   was already absent) and `false` when deletion was rejected (e.g. a
 *   non-configurable own property).
 * * [`StatorStatus::StatorStatusInvalidArg`] when `obj`, `key`, or `out` is
 *   null, or when the key bytes are not valid UTF-8.
 *
 * # Safety
 * * `obj` must be either null or a valid, live [`StatorObject`] pointer.
 * * `key` must be valid for reads of `key_len` bytes (or null).
 * * `out` must be either null or a valid pointer to a `bool`.
 */
enum StatorStatus stator_object_delete_property(struct StatorObject *obj,
                                                const char *key,
                                                size_t key_len,
                                                bool *out);

/**
 * Invoke a callable [`StatorValue`] with `argc` arguments and, on success,
 * write the returned value to `*out_val`.
 *
 * This first slice only supports native functions installed via
 * [`stator_function_template_get_function`] or returned through the FFI by
 * a native callback — i.e. values whose internal representation is a
 * reference-counted [`NativeFn`].  Bytecode-backed function values
 * ([`StatorValueInner::Function`]) cannot yet be invoked through this API
 * because the FFI does not yet model `new.target` or bytecode-function call
 * frames for direct embedder calls; calling such a value returns
 * [`StatorStatus::StatorStatusUnsupported`].  Construct semantics are
 * likewise deferred.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when the native function ran to
 *   completion; `*out_val` holds the (caller-owned) result.
 * * [`StatorStatus::StatorStatusException`] when the native callback
 *   returned an `Err`.  The isolate's pending exception is populated.
 * * [`StatorStatus::StatorStatusUnsupported`] when `callable` is not a
 *   native function (e.g. bytecode function, plain object, primitive).
 * * [`StatorStatus::StatorStatusInvalidArg`] when `ctx`, `callable`, or
 *   `out_val` is null, when `argc` is negative, or when `args` is null
 *   while `argc > 0`.
 *
 * `recv` is used as the native callback receiver (`this`).  A null receiver is
 * treated as JavaScript `undefined`.
 *
 * # Safety
 * * `ctx` must be a valid, live [`StatorContext`] pointer.
 * * `callable` must be either null or a valid, live [`StatorValue`] pointer.
 * * `recv` must be either null or a valid, live [`StatorValue`] pointer.
 * * `args` must be valid for `argc` `*const StatorValue` reads when `argc > 0`
 *   (or null when `argc == 0`).  Each non-null element must point at a
 *   valid, live [`StatorValue`].
 * * `out_val` must be either null or a valid pointer to a `*mut StatorValue`.
 */
enum StatorStatus stator_value_call(struct StatorContext *ctx,
                                    const struct StatorValue *callable,
                                    const struct StatorValue *recv,
                                    int32_t argc,
                                    const struct StatorValue *const *args,
                                    struct StatorValue **out_val);

/**
 * Register a native function named `name` on `ctx`.
 *
 * After registration, JavaScript code running via [`stator_script_run`] can
 * call `name(…)` as a global function.  The C `callback` is invoked with the
 * active context, an array of argument pointers (valid only for the duration
 * of the call), and the argument count.
 *
 * The name `"console"` has special semantics: if not yet defined it creates a
 * plain object; the function is then installed as `console.<method>` where
 * `<method>` is derived from the dot notation in `name`.  For example,
 * `name = "console.log"` registers `log` on the `console` object.
 *
 * Does nothing when `ctx` or `name` is null.
 *
 * # Safety
 * - `ctx` must be a valid, live [`StatorContext`] pointer.
 * - `name` must be a valid, null-terminated C string.
 * - `callback` must remain callable for the lifetime of `ctx`.
 */
void stator_register_native_function(struct StatorContext *ctx,
                                     const char *name,
                                     StatorNativeCallback callback);

/**
 * Return the number of arguments passed to this call.
 *
 * Returns `0` when `info` is null.
 *
 * # Safety
 * `info` must be either null or a valid pointer to a live
 * [`StatorFunctionCallbackInfo`].
 */
int32_t stator_function_callback_info_length(const struct StatorFunctionCallbackInfo *info);

/**
 * Return a pointer to the argument at position `index`.
 *
 * The returned pointer is valid only for the duration of the callback
 * invocation.  Returns a null pointer if `info` is null or `index` is out of
 * range.
 *
 * # Safety
 * `info` must be either null or a valid pointer to a live
 * [`StatorFunctionCallbackInfo`].
 */
const struct StatorValue *stator_function_callback_info_get(const struct StatorFunctionCallbackInfo *info,
                                                            int32_t index);

/**
 * Return the receiver (`this`) associated with this call.
 *
 * The returned pointer is valid only for the duration of the callback
 * invocation.  Returns a null pointer when `info` is null.
 *
 * # Safety
 * `info` must be either null or a valid pointer to a live
 * [`StatorFunctionCallbackInfo`].
 */
const struct StatorValue *stator_function_callback_info_get_this(const struct StatorFunctionCallbackInfo *info);

/**
 * Return the isolate associated with this call.
 *
 * Returns a null pointer if `info` is null.
 *
 * # Safety
 * `info` must be either null or a valid pointer to a live
 * [`StatorFunctionCallbackInfo`].
 */
struct StatorIsolate *stator_function_callback_info_get_isolate(const struct StatorFunctionCallbackInfo *info);

/**
 * Create a new function template associated with `isolate`.
 *
 * Returns a null pointer if `isolate` is null.  The caller must eventually
 * pass the returned pointer to [`stator_function_template_destroy`].
 *
 * # Safety
 * - `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 * - `callback` must remain valid for the lifetime of the template.
 */
struct StatorFunctionTemplate *stator_function_template_new(struct StatorIsolate *isolate,
                                                            StatorFunctionTemplateCallback callback);

/**
 * Destroy a function template previously created with
 * [`stator_function_template_new`].
 *
 * Does nothing if `tmpl` is null.
 *
 * # Safety
 * `tmpl` must be a non-null pointer returned by
 * [`stator_function_template_new`] and must not be used again after this call.
 */
void stator_function_template_destroy(struct StatorFunctionTemplate *tmpl);

/**
 * Return the instance template associated with a function template.
 *
 * The returned pointer is borrowed and owned by `tmpl`; callers must not pass
 * it to [`stator_object_template_destroy`]. Properties set on it are installed
 * as own properties when the function template is applied to a DOM wrapper.
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorFunctionTemplate`] pointer.
 */
struct StatorObjectTemplate *stator_function_template_instance_template(struct StatorFunctionTemplate *tmpl);

/**
 * Return the prototype template associated with a function template.
 *
 * The returned pointer is borrowed and owned by `tmpl`; callers must not pass
 * it to [`stator_object_template_destroy`]. Properties set on it are installed
 * on the DOM wrapper prototype object.
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorFunctionTemplate`] pointer.
 */
struct StatorObjectTemplate *stator_function_template_prototype_template(struct StatorFunctionTemplate *tmpl);

/**
 * Copy parent template inheritance metadata into `tmpl`.
 *
 * Parent instance-template properties that do not already exist are copied as
 * defaults. The child's prototype template receives a prototype-template link
 * to a deep snapshot of the parent's prototype template, producing a predictable
 * prototype chain for DOM wrapper instances.
 *
 * # Safety
 * `tmpl` and `parent` must be valid, live [`StatorFunctionTemplate`] pointers.
 */
enum StatorStatus stator_function_template_inherit(struct StatorFunctionTemplate *tmpl,
                                                   const struct StatorFunctionTemplate *parent);

/**
 * Create a signature requiring receivers created from `receiver`.
 *
 * Returns null when `receiver` is null.
 *
 * # Safety
 * `receiver` must be either null or a valid, live [`StatorFunctionTemplate`]
 * pointer.
 */
struct StatorSignature *stator_signature_new(const struct StatorFunctionTemplate *receiver);

/**
 * Destroy a signature created by [`stator_signature_new`].
 *
 * # Safety
 * `signature` must be either null or a pointer returned by
 * [`stator_signature_new`] that has not already been destroyed.
 */
void stator_signature_destroy(struct StatorSignature *signature);

/**
 * Attach a receiver signature to a function template.
 *
 * The receiver template id is copied into `tmpl`, so the caller may destroy
 * `signature` immediately after this call. Passing a null signature clears any
 * existing signature. Cross-isolate signatures are rejected.
 *
 * # Safety
 * `tmpl` must be a valid, live [`StatorFunctionTemplate`] pointer. `signature`
 * must be either null or a valid [`StatorSignature`] pointer.
 */
enum StatorStatus stator_function_template_set_signature(struct StatorFunctionTemplate *tmpl,
                                                         const struct StatorSignature *signature);

/**
 * Test whether `value` is an instance of `tmpl`.
 *
 * This checks DOM wrappers created by applying `tmpl` or a function template
 * that inherited from `tmpl`. Non-wrapper values, null pointers, and invalidated
 * wrappers return `false`.
 *
 * # Safety
 * `tmpl` and `value` must be either null or valid, live pointers.
 */
bool stator_function_template_has_instance(const struct StatorFunctionTemplate *tmpl,
                                           const struct StatorValue *value);

/**
 * Produce a [`StatorValue`] representing the function described by `tmpl`.
 *
 * The returned value has type `"function"` and can be installed into a
 * context's global environment via [`stator_context_global_set`], after which
 * JavaScript code run with [`stator_script_run`] can call it as a global
 * function.
 *
 * Returns a null pointer if `tmpl` is null.  The caller owns the returned
 * pointer and must eventually pass it to [`stator_value_destroy`] (or let a
 * handle scope manage it).
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorFunctionTemplate`]
 * pointer.
 */
struct StatorValue *stator_function_template_get_function(const struct StatorFunctionTemplate *tmpl,
                                                          struct StatorContext *_ctx);

/**
 * Install a value into the context's global environment under `name`.
 *
 * After this call, JavaScript code running via [`stator_script_run`] can
 * reference `name` as a global variable.  For function values (created via
 * [`stator_function_template_get_function`] or
 * [`stator_value_new_*`][stator_value_new_number]), the callable is installed
 * so that scripts can invoke it.
 *
 * Does nothing if `ctx` or `name` is null.  A null `val` installs
 * `undefined`.
 *
 * # Safety
 * - `ctx` must be a valid, live [`StatorContext`] pointer.
 * - `name` must be a valid, null-terminated C string.
 * - `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
void stator_context_global_set(struct StatorContext *ctx,
                               const char *name,
                               const struct StatorValue *val);

/**
 * Wrap a DOM object wrapper as an identity-preserving [`StatorValue`].
 *
 * Multiple calls for the same wrapper return values that materialize to the
 * same JS object, so script-visible comparisons such as
 * `document.documentElement === document.documentElement` work without a V8
 * wrapper.  The wrapper must remain valid until all returned values and script
 * aliases have been released or [`stator_dom_object_wrap_invalidate`] has been
 * called.
 *
 * Returns null when `wrap` is null or its owning isolate is null.
 *
 * # Safety
 * `wrap` must be either null or a valid, live [`StatorDomObjectWrap`] pointer.
 */
struct StatorValue *stator_dom_object_wrap_as_value(struct StatorDomObjectWrap *wrap);

/**
 * Return the originating DOM wrapper for a value produced by
 * [`stator_dom_object_wrap_as_value`].
 *
 * Returns null for primitives, ordinary objects, tag-only object values, and
 * DOM wrapper values that have since been invalidated.
 *
 * # Safety
 * `val` must be either null or a valid, live [`StatorValue`] pointer.
 */
struct StatorDomObjectWrap *stator_value_as_dom_object_wrap(const struct StatorValue *val);

/**
 * Invalidate a DOM object wrapper's script-visible materialization.
 *
 * Existing JS aliases to the materialized object remain safe to touch, but
 * generated DOM accessor thunks stop dereferencing the raw wrapper pointer and
 * return `undefined`.
 *
 * # Safety
 * `wrap` must be either null or a valid, live [`StatorDomObjectWrap`] pointer.
 */
void stator_dom_object_wrap_invalidate(struct StatorDomObjectWrap *wrap);

/**
 * Install a DOM object wrapper as a named global on `ctx`.
 *
 * The installed value is backed by a Stator `PlainObject` whose enumerable
 * properties are snapshotted from the wrapper's named-property enumerator and
 * own-property list at install time.  Reads of those properties dispatch back
 * to the wrapper's named getter; writes dispatch back only when the wrapper has
 * a named setter installed.  This lets embedders expose P0 DOM globals such as
 * `document.title` without V8.
 *
 * The global path shares the same cached materialization as
 * [`stator_dom_object_wrap_as_value`], preserving identity with wrapper values
 * returned from getters and methods.
 *
 * Returns:
 * * [`StatorStatus::StatorStatusOk`] when the global was installed.
 * * [`StatorStatus::StatorStatusException`] when materializing the wrapper's
 *   own properties triggers a descriptor callback exception.
 * * [`StatorStatus::StatorStatusInvalidArg`] when `ctx`, `name`, or `wrap` is
 *   null, when `name` is not valid UTF-8, or when `wrap` belongs to a
 *   different isolate than `ctx`.
 *
 * # Safety
 * - `ctx` must be a valid, live [`StatorContext`] pointer.
 * - `name` must be a valid, null-terminated C string.
 * - `wrap` must be a valid, live [`StatorDomObjectWrap`] pointer. It must
 *   remain alive until no script aliases can observe it, or must be invalidated
 *   via [`stator_dom_object_wrap_invalidate`] before destruction.
 */
enum StatorStatus stator_context_global_set_dom_object_wrap(struct StatorContext *ctx,
                                                            const char *name,
                                                            struct StatorDomObjectWrap *wrap);

/**
 * Apply a function template's instance/prototype templates to a DOM wrapper.
 *
 * Instance-template properties are installed as own properties on the wrapper.
 * Prototype-template properties are installed on an inherited prototype object.
 * The template contents are snapshotted at call time so later template changes
 * do not mutate already-applied wrappers.
 *
 * Returns [`StatorStatus::StatorStatusInvalidArg`] for null pointers,
 * cross-isolate templates, or invalidated wrappers.
 *
 * # Safety
 * `wrap` and `tmpl` must be valid, live pointers owned by the same isolate.
 */
enum StatorStatus stator_dom_object_wrap_apply_function_template(struct StatorDomObjectWrap *wrap,
                                                                 const struct StatorFunctionTemplate *tmpl);

/**
 * Create an empty snapshot callback manifest.
 */
struct StatorSnapshotManifest *stator_snapshot_manifest_create(void);

/**
 * Destroy a snapshot callback manifest. Passing null is a no-op.
 *
 * # Safety
 * `manifest` must be null or a pointer returned by [`stator_snapshot_manifest_create`].
 */
void stator_snapshot_manifest_destroy(struct StatorSnapshotManifest *manifest);

/**
 * Register a callback id in a manifest using the function-template callback ABI.
 *
 * `ctx` may be null for validation-only manifests; callbacks restored from such
 * a manifest return `undefined` if invoked. STSM/STWC runtime application should
 * pass the target context so callbacks are reinstalled against that isolate.
 *
 * # Safety
 * `manifest` must be valid, `id` must point to `id_len` bytes, and `callback`
 * must remain callable while loaded snapshot globals may invoke it.
 */
enum StatorStatus stator_snapshot_manifest_register_native_function(struct StatorSnapshotManifest *manifest,
                                                                    struct StatorContext *ctx,
                                                                    const char *id,
                                                                    size_t id_len,
                                                                    struct Option_StatorFunctionTemplateCallback callback);

/**
 * Return the number of ids registered in `manifest`.
 *
 * # Safety
 * `manifest` must be null or a valid manifest pointer.
 */
size_t stator_snapshot_manifest_len(const struct StatorSnapshotManifest *manifest);

/**
 * Construct an STWC build binding populated from the current FFI library.
 */
struct StatorSnapshotBuildBinding *stator_snapshot_build_binding_create_current(void);

/**
 * Destroy an STWC build binding. Passing null is a no-op.
 *
 * # Safety
 * `binding` must be null or returned by [`stator_snapshot_build_binding_create_current`].
 */
void stator_snapshot_build_binding_destroy(struct StatorSnapshotBuildBinding *binding);

/**
 * Override a string field in an STWC build binding.
 *
 * `field` accepts `ffi_crate_ver`, `commit_id`, `target_triple`, `os`, `arch`,
 * `cargo_profile`, or `engine_crate_ver`.
 *
 * # Safety
 * `binding` must be valid and `value` must point to `value_len` UTF-8 bytes.
 */
enum StatorStatus stator_snapshot_build_binding_set_string(struct StatorSnapshotBuildBinding *binding,
                                                           const char *field,
                                                           size_t field_len,
                                                           const char *value,
                                                           size_t value_len);

/**
 * Override the packed FFI ABI version in an STWC build binding.
 *
 * # Safety
 * `binding` must be valid.
 */
enum StatorStatus stator_snapshot_build_binding_set_ffi_abi_version(struct StatorSnapshotBuildBinding *binding,
                                                                    uint32_t version);

/**
 * Override a 32-byte hash field in an STWC build binding.
 *
 * # Safety
 * `binding` must be valid and `bytes32` must point to exactly 32 readable bytes.
 */
enum StatorStatus stator_snapshot_build_binding_set_hash(struct StatorSnapshotBuildBinding *binding,
                                                         enum StatorSnapshotBuildHashField field,
                                                         const uint8_t *bytes32);

/**
 * Classify a snapshot blob by magic bytes without fully decoding it.
 *
 * # Safety
 * `data` must point to `len` readable bytes and out-pointers must be valid when non-null.
 */
enum StatorStatus stator_snapshot_blob_classify(const uint8_t *data,
                                                size_t len,
                                                enum StatorSnapshotKind *out_kind,
                                                enum StatorSnapshotErrorKind *out_error,
                                                struct StatorSnapshotReport **out_report);

/**
 * Validate and decode a snapshot blob without mutating runtime state.
 *
 * STSM and STWC require a matching callback manifest. STWC also requires a
 * matching build binding; null binding means the current library defaults.
 *
 * # Safety
 * Pointers must be valid for the duration of this call.
 */
enum StatorStatus stator_snapshot_blob_validate(const uint8_t *data,
                                                size_t len,
                                                const struct StatorSnapshotManifest *manifest,
                                                const struct StatorSnapshotBuildBinding *binding,
                                                struct StatorSnapshotReport **out_report);

/**
 * Apply a supported snapshot's globals to an existing context.
 *
 * This API intentionally restores the implemented globals state only. It does
 * not claim complete warm-context realm/intrinsics restoration; embedders must
 * still run the missing runtime hook before using STWC as a full mksnapshot
 * equivalent.
 *
 * # Safety
 * `ctx` must be valid and blob/manifest/binding pointers must remain valid.
 */
enum StatorStatus stator_snapshot_blob_apply_to_context(struct StatorContext *ctx,
                                                        const uint8_t *data,
                                                        size_t len,
                                                        const struct StatorSnapshotManifest *manifest,
                                                        const struct StatorSnapshotBuildBinding *binding,
                                                        struct StatorSnapshotReport **out_report);

/**
 * Create a context and apply a supported snapshot blob's globals to it.
 *
 * Full warm-context realm creation remains unsupported; see the returned report
 * and `docs/snapshot.md` for the missing runtime hook. On failure no context is
 * returned.
 *
 * # Safety
 * `isolate` must be valid and out/blob pointers must be valid when non-null.
 */
enum StatorStatus stator_context_new_from_snapshot_blob(struct StatorIsolate *isolate,
                                                        const uint8_t *data,
                                                        size_t len,
                                                        const struct StatorSnapshotManifest *manifest,
                                                        const struct StatorSnapshotBuildBinding *binding,
                                                        struct StatorContext **out_context,
                                                        struct StatorSnapshotReport **out_report);

/**
 * Create an isolate and context, then apply a supported snapshot blob's globals.
 *
 * `out_context` receives the created context on success. On failure both the
 * context and isolate are destroyed and null is returned.
 *
 * # Safety
 * Blob/manifest/binding/out pointers must be valid when non-null.
 */
struct StatorIsolate *stator_isolate_new_from_snapshot_blob(const uint8_t *data,
                                                            size_t len,
                                                            const struct StatorSnapshotManifest *manifest,
                                                            const struct StatorSnapshotBuildBinding *binding,
                                                            struct StatorContext **out_context,
                                                            struct StatorSnapshotReport **out_report);

/**
 * Destroy a snapshot report. Passing null is a no-op.
 *
 * # Safety
 * `report` must be null or a pointer returned through a snapshot API out-param.
 */
void stator_snapshot_report_destroy(struct StatorSnapshotReport *report);

/**
 * Return a report's snapshot kind.
 *
 * # Safety
 * `report` must be null or valid.
 */
enum StatorSnapshotKind stator_snapshot_report_kind(const struct StatorSnapshotReport *report);

/**
 * Return a report's error kind.
 *
 * # Safety
 * `report` must be null or valid.
 */
enum StatorSnapshotErrorKind stator_snapshot_report_error_kind(const struct StatorSnapshotReport *report);

/**
 * Return the compatibility/error field name, or an empty string.
 *
 * # Safety
 * `report` must be null or valid.
 */
const char *stator_snapshot_report_field(const struct StatorSnapshotReport *report);

/**
 * Return the human-readable error message, or an empty string.
 *
 * # Safety
 * `report` must be null or valid.
 */
const char *stator_snapshot_report_message(const struct StatorSnapshotReport *report);

/**
 * Return how many globals were decoded or applied by the snapshot operation.
 *
 * # Safety
 * `report` must be null or valid.
 */
size_t stator_snapshot_report_applied_global_count(const struct StatorSnapshotReport *report);

/**
 * Open a new handle scope on `isolate`.
 *
 * All [`StatorValue`] handles created after this call (and before the
 * corresponding [`stator_handle_scope_close`]) are owned by the returned
 * scope and will be destroyed automatically when the scope is closed.
 *
 * Returns a null pointer if `isolate` is null.  The caller must eventually
 * pass the returned pointer to [`stator_handle_scope_close`].
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorHandleScope *stator_handle_scope_new(struct StatorIsolate *isolate);

/**
 * Close a handle scope and destroy all values registered with it.
 *
 * After this call, all [`StatorValue`] pointers that were created while
 * `scope` was the active scope are invalid.  The previous scope (if any) is
 * restored as the active scope on the isolate.
 *
 * Does nothing if `scope` is null.
 *
 * # Safety
 * - `scope` must be a non-null pointer returned by [`stator_handle_scope_new`].
 * - `scope` must be the *innermost* open scope on its isolate (i.e. handle
 *   scopes must be closed in LIFO order).
 * - `scope` must not be used again after this call.
 */
void stator_handle_scope_close(struct StatorHandleScope *scope);

/**
 * Open a new escapable handle scope on `isolate`.
 *
 * Returns a null pointer if `isolate` is null.  The caller must eventually
 * pass the returned pointer to [`stator_escapable_handle_scope_close`].
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorEscapableHandleScope *stator_escapable_handle_scope_new(struct StatorIsolate *isolate);

/**
 * Escape `val` from `scope`, promoting it into the enclosing scope.
 *
 * Removes `val` from `scope`'s tracked handles (so it will not be destroyed
 * when the scope is closed) and, if there is an enclosing scope, registers
 * it there.  If there is no enclosing scope the caller takes ownership and
 * must eventually pass `val` to [`stator_value_destroy`].
 *
 * Returns `val` unchanged (for convenient chaining in C/C++ callers), or a
 * null pointer if `scope` or `val` is null.
 *
 * # Safety
 * - `scope` must be a non-null, valid pointer to a live
 *   [`StatorEscapableHandleScope`].
 * - `val` must be a non-null pointer that is currently registered with
 *   `scope` (i.e. it was created while `scope` was the active scope).
 * - Each value may only be escaped once.
 */
struct StatorValue *stator_escapable_handle_scope_escape(struct StatorEscapableHandleScope *scope,
                                                         struct StatorValue *val);

/**
 * Close an escapable handle scope and destroy all non-escaped values.
 *
 * Equivalent in behaviour to [`stator_handle_scope_close`] for the escapable
 * variant.
 *
 * # Safety
 * - `scope` must be a non-null pointer returned by
 *   [`stator_escapable_handle_scope_new`].
 * - `scope` must be the innermost open scope on its isolate.
 * - `scope` must not be used again after this call.
 */
void stator_escapable_handle_scope_close(struct StatorEscapableHandleScope *scope);

/**
 * Create a new, empty object template associated with `isolate`.
 *
 * Returns a null pointer if `isolate` is null.  The caller must eventually
 * pass the returned pointer to [`stator_object_template_destroy`].
 *
 * # Safety
 * `isolate` must be a non-null, valid pointer to a live [`StatorIsolate`].
 */
struct StatorObjectTemplate *stator_object_template_new(struct StatorIsolate *isolate);

/**
 * Destroy an object template previously created with
 * [`stator_object_template_new`].
 *
 * Does nothing if `tmpl` is null.
 *
 * # Safety
 * `tmpl` must be a non-null pointer returned by
 * [`stator_object_template_new`] and must not be used again after this call.
 */
void stator_object_template_destroy(struct StatorObjectTemplate *tmpl);

/**
 * Set a named property on the object template.
 *
 * When a new instance is created via [`stator_object_template_new_instance`],
 * it will have this property pre-installed.  Does nothing if any argument is
 * null.
 *
 * # Safety
 * - `tmpl` must be a valid, live [`StatorObjectTemplate`] pointer.
 * - `key` must be a valid, null-terminated C string.
 * - `val` must be a valid, live [`StatorValue`] pointer.
 */
void stator_object_template_set(struct StatorObjectTemplate *tmpl,
                                const char *key,
                                const struct StatorValue *val);

/**
 * Install an aggregated named-property handler on an object template.
 *
 * Function templates snapshot this handler onto DOM wrappers when their
 * instance template is applied. Returns InvalidArg for null pointers or an
 * all-null handler.
 *
 * # Safety
 * - `tmpl` must be a valid, live [`StatorObjectTemplate`] pointer.
 * - `handler` must point to a readable [`StatorDomNamedHandler`].
 */
enum StatorStatus stator_object_template_install_named_handler(struct StatorObjectTemplate *tmpl,
                                                               const struct StatorDomNamedHandler *handler);

/**
 * Install an aggregated indexed-property handler on an object template.
 *
 * Function templates snapshot this handler onto DOM wrappers when their
 * instance template is applied. Returns InvalidArg for null pointers or an
 * all-null handler.
 *
 * # Safety
 * - `tmpl` must be a valid, live [`StatorObjectTemplate`] pointer.
 * - `handler` must point to a readable [`StatorDomIndexedHandler`].
 */
enum StatorStatus stator_object_template_install_indexed_handler(struct StatorObjectTemplate *tmpl,
                                                                 const struct StatorDomIndexedHandler *handler);

/**
 * Set the number of internal fields on objects created from this template.
 *
 * Internal fields are opaque embedder-owned slots (similar to V8's
 * `SetInternalFieldCount`).  Does nothing if `tmpl` is null.
 *
 * # Safety
 * `tmpl` must be a valid, live [`StatorObjectTemplate`] pointer.
 */
void stator_object_template_set_internal_field_count(struct StatorObjectTemplate *tmpl,
                                                     int32_t count);

/**
 * Return the internal field count configured on this template.
 *
 * Returns `0` if `tmpl` is null.
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorObjectTemplate`] pointer.
 */
int32_t stator_object_template_internal_field_count(const struct StatorObjectTemplate *tmpl);

/**
 * Return this object template's mutable prototype template.
 *
 * The returned pointer is borrowed and owned by `tmpl`; callers must not pass
 * it to [`stator_object_template_destroy`]. Returns null when `tmpl` is null.
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorObjectTemplate`] pointer.
 */
struct StatorObjectTemplate *stator_object_template_prototype_template(struct StatorObjectTemplate *tmpl);

/**
 * Create a new [`StatorObject`] instance from an object template.
 *
 * The returned object has all properties defined on the template pre-installed.
 * Returns a null pointer if `tmpl` is null.  The caller owns the returned
 * pointer and must eventually pass it to [`stator_object_destroy`].
 *
 * # Safety
 * `tmpl` must be either null or a valid, live [`StatorObjectTemplate`] pointer.
 */
struct StatorObject *stator_object_template_new_instance(const struct StatorObjectTemplate *tmpl);

/**
 * Return the structured [`StatorMessageKind`] of `msg`.
 *
 * Returns [`StatorMessageKind::StatorMessageKindUnknown`] when `msg` is null.
 *
 * # Safety
 * `msg` must be either null or a valid pointer to a live [`StatorMessage`].
 */
enum StatorMessageKind stator_message_kind(const struct StatorMessage *msg);

/**
 * Return a null-terminated UTF-8 description of `msg`, or null when `msg`
 * is null.
 *
 * The returned pointer is borrowed: it is valid as long as `msg` is alive
 * and must not be freed by the caller.
 *
 * # Safety
 * `msg` must be either null or a valid pointer to a live [`StatorMessage`].
 */
const char *stator_message_text(const struct StatorMessage *msg);

/**
 * Return the script resource name associated with `msg`, or null when no
 * resource name was attached (e.g. for embedder-thrown exceptions) or
 * `msg` is null.
 *
 * The returned pointer is borrowed: it is valid as long as `msg` is alive
 * and must not be freed by the caller.
 *
 * # Safety
 * `msg` must be either null or a valid pointer to a live [`StatorMessage`].
 */
const char *stator_message_resource_name(const struct StatorMessage *msg);

